CREATE VIEW `dim_video_cn_accountinfo_view` (`id` COMMENT "id", `account` COMMENT "账户id", `nick` COMMENT "昵称", `sex` COMMENT "性别", `create_time` COMMENT "创建时间", `last_login_time` COMMENT "上次登录时间", `chl2` COMMENT "chl2", `mt2` COMMENT "设备", `unique_cdreader_id` COMMENT "唯一设备id，account以及video_user_id一致", `current_language2` COMMENT "注册时语言", `corever2` COMMENT "corever2", `video_user_id` COMMENT "用户id", `adid` COMMENT "广告id", `status` COMMENT "用户状态：0 正常，1 禁用，2 审核中，3 审核拒绝", `source_chl` COMMENT "来源", `reg_country` COMMENT "注册国家", `agent` COMMENT "渠道商标识，来自uni-id-users.agent，Agent>=0为渠道商", `project_id` COMMENT "项目id", `promotion_id`, `tfid` COMMENT "投放Id", `reqid`, `middle_man_id` COMMENT "机构id", `PlusType`, `PlusExpireTime`, `LastLoginOS`, `reback_time` COMMENT "回传时间", `reback_active_time` COMMENT "回传激活时间", `reback` COMMENT "是否回传", `platform` COMMENT "平台", `balance` COMMENT "金豆余额", `appid` COMMENT "小程序id") AS SELECT `ods`.`a`.`Id`, `ods`.`a`.`Account`, `ods`.`a`.`Nick`, `ods`.`a`.`Sex`, `ods`.`a`.`CreateTime` AS `create_time`, `ods`.`a`.`LastLoginTime` AS `last_login_time`, `ods`.`a`.`Chl2`, `ods`.`a`.`Mt2`, `ods`.`a`.`UniqueCdReaderId` AS `unique_cdreader_id`, `ods`.`a`.`CurrentLanguage2` AS `current_language2`, `ods`.`a`.`CoreVer2`, `ods`.`a`.`VideoUserId` AS `video_user_id`, `ods`.`a`.`AdId`, `ods`.`a`.`Status`, `ods`.`a`.`SourceChl` AS `source_chl`, `ods`.`a`.`RegCountry` AS `reg_country`, `ods`.`a`.`Agent`, `ods`.`a`.`project_id`, `ods`.`a`.`promotion_id`, `ods`.`a`.`TFID`, `ods`.`a`.`ReqId`, `ods`.`a`.`MiddleManId` AS `middle_man_id`, `ods`.`a`.`PlusType`, `ods`.`a`.`PlusExpireTime`, `ods`.`a`.`LastLoginOS`, `ods`.`a`.`RebackTime` AS `reback_time`, `ods`.`a`.`RebackActiveTime` AS `reback_active_time`, `ods`.`a`.`Reback`, `b`.`platform`, `b`.`balance`, `b`.`appid`
FROM `ods`.`ods_tidb_cdvideo_tidb_xcx_accountinfo` AS `a` LEFT OUTER JOIN (SELECT `ods`.`ods_tidb_cdvideo_tidb_xcx_sync_uni_id_users`.`_id`, `ods`.`ods_tidb_cdvideo_tidb_xcx_sync_uni_id_users`.`platform`, `ods`.`ods_tidb_cdvideo_tidb_xcx_sync_uni_id_users`.`balance`, `ods`.`ods_tidb_cdvideo_tidb_xcx_sync_uni_id_users`.`appid`
FROM `ods`.`ods_tidb_cdvideo_tidb_xcx_sync_uni_id_users`) `b` ON `ods`.`a`.`UniqueCdReaderId` = `b`.`_id`
WHERE `ods`.`a`.`Status` = 0;
